const raw = $input.first().json;
const params = raw.parameters ?? {};
const title = params.title ?? params.case_title ?? null;
const description = params.description ?? params.summary ?? 'Created by YAOC2 agent.';
const severity = params.severity ?? 2;
const tlp = params.tlp ?? 2;
const tags = params.tags ?? ['yaoc2', 'automated'];
const observables = params.observables ?? [];
const tasks = params.tasks ?? [];
if (!title) throw new Error('Sandbox: parameters.title or parameters.case_title is required');
const proposedActionId = raw.proposed_action_id ?? 'unknown';
return [{ json: { title, description, severity, tlp, tags, observables, tasks, proposed_action_id: proposedActionId, requester: raw.requester } }];

const hive = $input.item.json;
const input = $('Normalise Input').first().json;
const caseId = hive._id ?? hive.id ?? null;
const caseNumber = hive.caseId ?? hive.number ?? null;
if (!caseId) throw new Error('TheHive case creation failed: ' + JSON.stringify(hive));
return [{ json: { ...input, case_id: caseId, case_number: caseNumber, case_url: $env.THEHIVE_URL + '/cases/' + caseId + '/details' } }];

const input = $('Parse Case ID').first().json;
return [{ json: {
  status: 'success',
  result_summary: `TheHive case #${input.case_number} created: ${input.title}. URL: ${input.case_url}`,
  raw_result_ref: input.case_url,
  case_id: input.case_id,
  case_number: input.case_number,
  case_url: input.case_url,
  proposed_action_id: input.proposed_action_id
} }];
